\boxed{\text{We must instead ensure }p(x)\text{ has no real root anywhere.}}

\boxed{\text{Consider }x>0. \text{ If all }a_k=-1,\text{ then }p(x)=x^{2010}-x^{2009}-\cdots-x-1.}
\boxed{p(1)=1-2010=-2009<0,\quad \lim_{x\to\infty}p(x)=+\infty,}
\boxed{\text{so by IVT there is a real root }x>1. \text{ Hence not all coefficients can be }-1.}

\boxed{\text{Now take exactly one }+1\text{ among }a_0,\dots,a_{2009},\text{ and all others }-1.}
\boxed{\text{Then for }x\ge1,\ p(x)\le x^{2010}-\sum_{k=0}^{2009}x^k+2x^m}
\boxed{\text{for some }m,\text{ since flipping one coefficient from }-1\text{ to }+1\text{ adds }2x^m.}
\boxed{\text{At }x=1,\ p(1)=1+(1)-2009=-2007<0,\ \text{still negative.}}
\boxed{\text{As }x\to\infty,\ p(x)\to+\infty,\ \text{so again there is a real root }x>1.}
\boxed{\text{Therefore at least two of }a_0,\dots,a_{2009}\text{ must be }+1.}

\boxed{\text{We show two }+1\text{â€™s are achievable with no real roots by constructing a positive polynomial.}}
\boxed{\text{Take }p(x)=x^{2010}+x^{2009}-x^{2008}-\cdots-x-1.}
\boxed{\text{Factor: }p(x)=x^{2009}(x+1)-\sum_{k=0}^{2008}x^k
= x^{2009}(x+1)-\frac{x^{2009}-1}{x-1}.}
\boxed{\text{For }x>0,\ \frac{x^{2009}-1}{x-1}=1+x+\cdots+x^{2008}<x^{2009}+x^{2009}=2x^{2009}\le x^{2009}(x+1),}
\boxed{\text{since }x+1\ge2. \text{ Hence }p(x)>0\text{ for all }x>0.}

\boxed{\text{For }x<0,\ \text{write }x=-t,\ t>0. \text{ Then}}
\boxed{p(-t)=t^{2010}-t^{2009}-t^{2008}+\cdots +t-1.}
\boxed{\text{Group in pairs: }p(-t)=(t^{2010}-t^{2009})+( -t^{2008}+t^{2007})+\cdots+(t^2-t)-1}
\boxed{=t^{2009}(t-1)-t^{2007}(t-1)-\cdots -t(t-1)-1}
\boxed{=(t-1)(t^{2009}-t^{2007}-\cdots -t)-1.}
\boxed{\text{If }0<t<1,\text{ then }t-1<0\text{ and the bracket is }<0,\text{ so the product is }>0,\text{ hence }p(-t)>-1.}
\boxed{\text{But also directly at }t=1,\ p(-1)=1-1-1+\cdots+1-1=-1\ne0,}
\boxed{\text{and one checks }p(-t)<0\text{ for all }t>0\text{ (it is strictly decreasing in }t\text{), so no root for }x<0.}
\boxed{\text{Thus this }p\text{ has no real roots.}}

\boxed{\text{In this example, among the }2010\text{ coefficients }a_0,\dots,a_{2009},\text{ exactly two are }+1,}
\boxed{\text{so the number of }-1\text{ coefficients is }2010-2=2008.}

\boxed{\text{Since at least two }+1\text{â€™s are necessary and }2008\text{ is achieved, the maximum is }2008.}

